// Fetch y parseo de todos los feeds RSS de noticias navieras
const feeds = [
  { company:'msc',    name:'MSC Cruceros',      rssUrl:'https://news.google.com/rss/search?q=MSC+cruceros&hl=es&gl=ES&ceid=ES:es',           groups:'811550587597467',  page:'guiacrucerista' },
  { company:'royal',  name:'Royal Caribbean',   rssUrl:'https://news.google.com/rss/search?q=Royal+Caribbean+cruceros&hl=es&gl=ES&ceid=ES:es',groups:'1116074769675601', page:'guiacrucerista' },
  { company:'costa',  name:'Costa Cruceros',    rssUrl:'https://news.google.com/rss/search?q=Costa+Cruceros&hl=es&gl=ES&ceid=ES:es',          groups:'1882092085657041', page:'guiacrucerista' },
  { company:'general',name:'Cruceros General',  rssUrl:'https://news.google.com/rss/search?q=cruceros+Mediterraneo+noticias&hl=es&gl=ES&ceid=ES:es', groups:'',           page:'guiacrucerista' },
  { company:'fluvial',name:'Cruceros Fluviales',rssUrl:'https://news.google.com/rss/search?q=cruceros+fluviales+Europa&hl=es&gl=ES&ceid=ES:es',      groups:'',           page:'guiacrucerista' }
];

const allItems = [];

for (const feed of feeds) {
  try {
    const response = await $http.get(feed.rssUrl, { headers: { 'User-Agent': 'Mozilla/5.0 GuiaCrucerista/1.0' } });
    const xml = response.data;
    const itemRegex = /<item>([\s\S]*?)<\/item>/g;
    let match;
    let count = 0;
    while ((match = itemRegex.exec(xml)) !== null && count < 2) {
      const c = match[1];
      const title   = (/<title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s.exec(c) || [])[1]?.trim() || '';
      const link    = (/<link>(.*?)<\/link>/.exec(c) || [])[1]?.trim() || '';
      const pubDate = (/<pubDate>(.*?)<\/pubDate>/.exec(c) || [])[1]?.trim() || '';
      const guid    = (/<guid[^>]*>(.*?)<\/guid>/.exec(c) || [])[1]?.trim() || link;
      const desc    = (/<description>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/s.exec(c) || [])[1]?.trim().replace(/<[^>]+>/g,'').substring(0,300) || '';
      const hoursOld = pubDate ? (Date.now() - new Date(pubDate).getTime()) / 3600000 : 99;
      if (title && link && hoursOld <= 8) {
        allItems.push({ json: { title, link, pubDate, guid, desc, company: feed.company, feedName: feed.name, groups: feed.groups, page: feed.page } });
        count++;
      }
    }
  } catch(e) {
    console.log('Error feed ' + feed.company + ': ' + e.message);
  }
}

return allItems.length ? allItems : [{ json: { skip: true, reason: 'Sin noticias nuevas en las últimas 8h' } }];

// Preparar archivo JSON para el script Playwright
const postText = $input.item.json.message?.content || $input.item.json.text || 'Noticia cruceros';
const groups   = $input.item.json.groups || '';
const page     = $input.item.json.page   || '';
const url      = $input.item.json.link   || '';
const company  = $input.item.json.company || 'general';

const postData = { text: postText, url, groups: groups ? groups.split(',') : [], page };
const tmpFile  = '/tmp/fb_noticias_' + Date.now() + '.json';

return [{ json: { postData, postJson: JSON.stringify(postData), tmpFile, company, postText, url, groups, page } }];

